final:
module top_module(
   // Outputs
   output reg toggle_out,
   // Inputs
   input clk,
   input in,
   input reset
);always @(posedge clk or posedge reset) begin
      if (reset) begin
         toggle_out <= 1'b0;
      end else if (in) begin
         toggle_out <= ~toggle_out;
      end
   end

endmodule
